import BaseSnipeBot from '../baseSnipeBot.js';
import retry from '../../utils/retry.js';
import logger from '../../utils/logger.js';
import { ethers } from 'ethers';
import UniswapV2Router02ABI from './abis/uniswapV2Router.js'; // Đổi tên để rõ ràng

class EvmAdapter extends BaseSnipeBot {
  constructor({ walletPrivateKey, chains, tslConfig, role }) {
    super({ walletPrivateKey, chains, tslConfig, role });
    this.supportedChains = {
      1: { name: 'ethereum', weth: '0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2' }, // Ethereum Mainnet
      56: { name: 'bsc', weth: '0xbb4CdB9CBd36B01bD1cBaEBF2De08d9173bc095c' }     // Binance Smart Chain
    };
  }

  async watchMempool(callback, chainId) {
    const chain = this.supportedChains[chainId];
    if (!chain) throw new Error(`Chain ID ${chainId} không hỗ trợ`);
    this.providers[chain.name].on('pending', async (txHash) => {
      const tx = await retry(() => this.providers[chain.name].getTransaction(txHash));
      if (tx) callback(tx);
    });
  }

  async buyToken(chainId, tokenAddress, amount, gasPrice) {
    const chain = this.supportedChains[chainId];
    if (!chain) throw new Error(`Chain ID ${chainId} không hỗ trợ`);
    const router = new ethers.Contract(
      this.getRouterAddress(chainId),
      UniswapV2Router02ABI,
      this.wallets[chain.name]
    );
    const tx = await retry(() =>
      router.swapExactETHForTokens(
        0, // amountOutMin
        [chain.weth, tokenAddress], // Path: WETH/WBNB -> Token
        this.wallets[chain.name].address,
        Math.floor(Date.now() / 1000) + 60 * 10,
        { value: ethers.parseEther(amount), ...(gasPrice || {}) }
      )
    );
    await logger(`Mua token ${tokenAddress} với ${amount} ETH trên ${chain.name}`);
    return tx.wait();
  }

  async sellToken(chainId, tokenAddress, amount, gasPrice) {
    const chain = this.supportedChains[chainId];
    if (!chain) throw new Error(`Chain ID ${chainId} không hỗ trợ`);
    const router = new ethers.Contract(
      this.getRouterAddress(chainId),
      UniswapV2Router02ABI,
      this.wallets[chain.name]
    );
    const tx = await retry(() =>
      router.swapExactTokensForETH(
        ethers.parseUnits(amount, 18),
        0, // amountOutMin
        [tokenAddress, chain.weth], // Path: Token -> WETH/WBNB
        this.wallets[chain.name].address,
        Math.floor(Date.now() / 1000) + 60 * 10,
        { ...(gasPrice || {}) }
      )
    );
    await logger(`Bán token ${tokenAddress} với ${amount} token trên ${chain.name}`);
    return tx.wait();
  }

  getRouterAddress(chainId) {
    const routers = {
      1: '0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D', // Uniswap V2 (Ethereum)
      56: '0x10ED43C718714eb63d5aA57B78B54704E256024E' // PancakeSwap V2 (BSC)
    };
    return routers[chainId] || routers[56]; // Mặc định BSC nếu chainId không xác định
  }
}

export default EvmAdapter;

import BaseSnipeBot from '../baseSnipeBot.js';
import retry from '../../utils/retry.js';
import logger from '../../utils/logger.js';
import * as nearAPI from 'near-api-js';
import config from '../../config.js';

class NearAdapter extends BaseSnipeBot {
  constructor({ walletPrivateKey, rpcUrl, networkId = 'testnet' }) {
    super({ walletPrivateKey, rpcUrl });
    this.networkId = networkId; // mainnet hoặc testnet
  }

  async initialize() {
    const { keyStores, connect } = nearAPI;
    const keyStore = new keyStores.InMemoryKeyStore();
    await keyStore.setKey(this.networkId, config.nearAccountId, nearAPI.utils.KeyPair.fromString(this.walletPrivateKey));
    this.provider = await connect({
      networkId: this.networkId,
      nodeUrl: this.rpcUrl,
      keyStore
    });
    this.wallet = await this.provider.account(config.nearAccountId);
    await logger(`NEAR Adapter khởi tạo với tài khoản: ${this.wallet.accountId}`);
  }

  async getTokenBalance(tokenAddress) {
    const balance = await this.wallet.viewFunction(tokenAddress, 'ft_balance_of', { account_id: this.wallet.accountId });
    return balance;
  }

  async watchMempool(callback) {
    this.provider.connection.provider.on('block', (block) => callback(block));
  }

  async buyToken(tokenAddress, amount) {
    const tx = await retry(() =>
      this.wallet.functionCall({
        contractId: 'v2.ref-finance.near', // Ref Finance
        methodName: 'ft_transfer_call',
        args: { receiver_id: tokenAddress, amount },
        gas: '30000000000000'
      })
    );
    await logger(`Mua token ${tokenAddress} với ${amount} NEAR`);
    return tx;
  }

  async sellToken(tokenAddress, amount) {
    const balance = await this.getTokenBalance(tokenAddress);
    if (balance < amount) throw new Error('Số dư token không đủ');
    const tx = await retry(() =>
      this.wallet.functionCall({
        contractId: tokenAddress,
        methodName: 'ft_transfer',
        args: { receiver_id: 'v2.ref-finance.near', amount },
        gas: '30000000000000'
      })
    );
    await logger(`Bán token ${tokenAddress} với ${amount} token`);
    return tx;
  }
}

export default NearAdapter;

import BaseSnipeBot from '../baseSnipeBot.js';
import retry from '../../utils/retry.js';
import logger from '../../utils/logger.js';
import { Connection, Keypair, PublicKey, Transaction, SystemProgram } from '@solana/web3.js';
import { TOKEN_PROGRAM_ID } from '@solana/spl-token';

class SolAdapter extends BaseSnipeBot {
  constructor({ walletPrivateKey, rpcUrl }) {
    super({ walletPrivateKey, rpcUrl });
  }

  async initialize() {
    this.provider = new Connection(this.rpcUrl, 'confirmed');
    this.wallet = Keypair.fromSecretKey(Uint8Array.from(JSON.parse(this.walletPrivateKey)));
    await logger(`Solana Adapter khởi tạo với ví: ${this.wallet.publicKey.toBase58()}`);
  }

  async watchMempool(callback) {
    this.provider.onPendingTransaction((tx) => callback(tx));
  }

  async getFeeEstimate() {
    const recentBlockhash = await this.provider.getRecentBlockhash();
    return recentBlockhash.feeCalculator.lamportsPerSignature;
  }

  async buyToken(tokenAddress, amount) {
    const fee = await this.getFeeEstimate();
    const tx = new Transaction().add(
      SystemProgram.transfer({
        fromPubkey: this.wallet.publicKey,
        toPubkey: new PublicKey('RAYDIUM_POOL_ADDRESS'), // Raydium pool
        lamports: amount * 1e9 + fee // amount + phí
      })
    );
    const result = await retry(() => this.provider.sendTransaction(tx, [this.wallet]));
    await logger(`Mua token ${tokenAddress} với ${amount} SOL`);
    return result;
  }

  async sellToken(tokenAddress, amount) {
    const fee = await this.getFeeEstimate();
    const tx = new Transaction().add(
      TOKEN_PROGRAM_ID.transfer({
        fromPubkey: this.wallet.publicKey,
        toPubkey: new PublicKey('RAYDIUM_POOL_ADDRESS'),
        amount: amount * 1e9,
        fee
      })
    );
    const result = await retry(() => this.provider.sendTransaction(tx, [this.wallet]));
    await logger(`Bán token ${tokenAddress} với ${amount} token`);
    return result;
  }
}

export default SolAdapter;

import BaseSnipeBot from '../baseSnipeBot.js';
import retry from '../../utils/retry.js';
import logger from '../../utils/logger.js';
import { JsonRpcProvider, Ed25519Keypair } from '@mysten/sui.js';

class SuiAdapter extends BaseSnipeBot {
  constructor({ walletPrivateKey, rpcUrl }) {
    super({ walletPrivateKey, rpcUrl });
  }

  async initialize() {
    this.provider = new JsonRpcProvider(this.rpcUrl);
    this.wallet = Ed25519Keypair.fromSecretKey(Buffer.from(this.walletPrivateKey, 'base64'));
    await logger(`SUI Adapter khởi tạo với ví: ${this.wallet.getPublicKey().toSuiAddress()}`);
  }

  async watchMempool(callback) {
    this.provider.subscribeToEvents({ onEvent: (event) => callback(event) });
  }

  async checkResources() {
    const resources = await this.provider.getOwnedObjects(this.wallet.getPublicKey().toSuiAddress());
    return resources.some(r => r.type === 'Coin<SUI>' && r.balance > 0);
  }

  async buyToken(tokenAddress, amount) {
    if (!(await this.checkResources())) throw new Error('Không đủ tài nguyên SUI');
    const tx = await retry(() =>
      this.provider.executeMoveCall({
        packageObjectId: 'CETUS_PACKAGE_ID',
        module: 'swap',
        function: 'swap',
        typeArguments: [tokenAddress],
        arguments: [amount],
        signer: this.wallet
      })
    );
    await logger(`Mua token ${tokenAddress} với ${amount} SUI`);
    return tx;
  }

  async sellToken(tokenAddress, amount) {
    if (!(await this.checkResources())) throw new Error('Không đủ tài nguyên SUI');
    const tx = await retry(() =>
      this.provider.executeMoveCall({
        packageObjectId: 'CETUS_PACKAGE_ID',
        module: 'swap',
        function: 'swap',
        typeArguments: [tokenAddress],
        arguments: [amount],
        signer: this.wallet
      })
    );
    await logger(`Bán token ${tokenAddress} với ${amount} token`);
    return tx;
  }
}

export default SuiAdapter;

import BaseSnipeBot from '../baseSnipeBot.js';
import retry from '../../utils/retry.js';
import logger from '../../utils/logger.js';
import { TonClient, JettonMaster } from '@ton/ton';

class TonAdapter extends BaseSnipeBot {
  constructor({ walletPrivateKey, rpcUrl }) {
    super({ walletPrivateKey, rpcUrl });
  }

  async initialize() {
    this.provider = new TonClient({ endpoint: this.rpcUrl });
    this.wallet = await this.provider.openWalletFromSecretKey(this.walletPrivateKey);
    await logger(`TON Adapter khởi tạo với ví: ${this.wallet.address}`);
  }

  async watchMempool(callback) {
    this.provider.on('transaction', (tx) => callback(tx));
  }

  async buyToken(tokenAddress, amount) {
    const jettonMaster = new JettonMaster(this.provider, tokenAddress);
    const tx = await retry(() =>
      this.wallet.send({
        to: jettonMaster.address,
        value: amount, // nanoTON
        data: jettonMaster.createTransferBody({
          jettonAmount: amount,
          toAddress: this.wallet.address
        })
      })
    );
    const receipt = await this.provider.waitForTransaction(tx.txId);
    await logger(`Mua JETTON ${tokenAddress} với ${amount} nanoTON`);
    return receipt;
  }

  async sellToken(tokenAddress, amount) {
    const jettonMaster = new JettonMaster(this.provider, tokenAddress);
    const tx = await retry(() =>
      this.wallet.send({
        to: jettonMaster.address,
        value: amount,
        data: jettonMaster.createTransferBody({
          jettonAmount: amount,
          toAddress: 'STON_FI_ADDRESS' // Địa chỉ STON.fi DEX
        })
      })
    );
    const receipt = await this.provider.waitForTransaction(tx.txId);
    await logger(`Bán JETTON ${tokenAddress} với ${amount} nanoTON`);
    return receipt;
  }
}

export default TonAdapter;

import BaseSnipeBot from '../baseSnipeBot.js';
import retry from '../../utils/retry.js';
import logger from '../../utils/logger.js';
import { ethers } from 'ethers';
import { UniswapV2Router02ABI } from './abis/uniswapV2Router.js';

class EvmAdapter extends BaseSnipeBot {
  constructor({ walletPrivateKey, chains, tslConfig, userId }) {
    super({ walletPrivateKey, chains, tslConfig, userId });
  }

  async watchMempool(callback, chain) {
    if (chain !== 'evm') return;
    this.providers[chain].on('pending', async (txHash) => {
      const tx = await retry(() => this.providers[chain].getTransaction(txHash));
      if (tx) callback(tx);
    });
  }

  async buyToken(chain, tokenAddress, amount, gasPrice) {
    if (chain !== 'evm') throw new Error('Chain không hỗ trợ');
    const router = new ethers.Contract(this.getRouterAddress(), UniswapV2Router02ABI, this.wallets[chain]);
    const tx = await retry(() =>
      router.swapExactETHForTokens(
        0,
        [ethers.constants.AddressZero, tokenAddress],
        this.wallets[chain].address,
        Math.floor(Date.now() / 1000) + 60 * 10,
        { value: ethers.parseEther(amount), ...(gasPrice || {}) }
      )
    );
    await logger(`Mua token ${tokenAddress} với ${amount} ETH trên ${chain}`);
    return tx.wait();
  }

  async sellToken(chain, tokenAddress, amount, gasPrice) {
    if (chain !== 'evm') throw new Error('Chain không hỗ trợ');
    const router = new ethers.Contract(this.getRouterAddress(), UniswapV2Router02ABI, this.wallets[chain]);
    const tx = await retry(() =>
      router.swapExactTokensForETH(
        ethers.parseUnits(amount, 18),
        0,
        [tokenAddress, ethers.constants.AddressZero],
        this.wallets[chain].address,
        Math.floor(Date.now() / 1000) + 60 * 10,
        { ...(gasPrice || {}) }
      )
    );
    await logger(`Bán token ${tokenAddress} với ${amount} token trên ${chain}`);
    return tx.wait();
  }

  getRouterAddress() {
    return '0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D';
  }
}

export default EvmAdapter;

import dotenv from 'dotenv';

dotenv.config();

export default {
  reserveWallet: '0xYourReserveWalletAddress',
  rpcUrls: {
    evm: 'https://eth.llamarpc.com'
  },
  nearAccountId: process.env.NEAR_ACCOUNT_ID,
  rpcUrls: {
    evm: process.env.RPC_EVM,
    ton: process.env.RPC_TON,
    near: process.env.RPC_NEAR,
    solana: process.env.RPC_SOLANA,
    sui: process.env.RPC_SUI
  },
  chainIds: {
    evm: 1,    // Ethereum Mainnet
    bsc: 56,   // Binance Smart Chain
    polygon: 137, // Polygon
    ton: 'ton-mainnet',
    near: 'near-testnet',
    solana: 'solana-mainnet',
    sui: 'sui-mainnet'
  },
  apiKeys: {
    coingecko: process.env.API_COINGECKO,
    binance: process.env.API_BINANCE,
    terminal: process.env.API_TERMINAL,
    telegram: process.env.TELEGRAM_TOKEN,
    discord: process.env.DISCORD_WEBHOOK
  },
  mongoUrl: process.env.MONGO_URL,
  ipfsUrl: process.env.IPFS_URL,
  redisUrl: process.env.REDIS_URL
};

import { Worker } from 'worker_threads';
import express from 'express';
import TransactionService from '../services/transactionService.js';
import NotificationService from '../services/notificationService.js';
import logger from '../utils/logger.js';

class BotController {
  constructor(botConfig) {
    this.transactionService = new TransactionService(botConfig);
    this.notificationService = new NotificationService({});
    this.app = express();
    this.state = 'stopped';
    this.workers = [];
  }

  async start() {
    this.state = 'running';
    await this.transactionService.initialize();
    await this.notificationService.initialize();
    this.setupApi();
    this.startWorker();
    await this.notificationService.sendNotification('Bot đã khởi động');
    await logger('BotController đã khởi động');
  }

  async stop() {
    this.state = 'stopped';
    this.workers.forEach(worker => worker.terminate());
    await this.notificationService.sendNotification('Bot đã dừng');
    await this.notificationService.close();
    await logger('BotController đã dừng');
  }

  setupApi() {
    this.app.use(express.json());
    this.app.post('/trade', async (req, res) => {
      const { action, tokenAddress, amount } = req.body;
      const tx = await this.executeTrade({ action, tokenAddress, amount });
      res.json(tx);
    });
    this.app.listen(3000, () => logger('API chạy trên port 3000'));
  }

  startWorker() {
    const worker = new Worker('./transactionWorker.js', { workerData: { config: this.transactionService.bot } });
    this.workers.push(worker);
    worker.on('message', msg => logger(`Worker: ${msg}`));
  }

  async executeTrade({ action, tokenAddress, amount }) {
    if (this.state !== 'running') throw new Error('Bot chưa chạy');
    return action === 'buy'
      ? await this.transactionService.buyToken(tokenAddress, amount)
      : await this.transactionService.sellToken(tokenAddress, amount);
  }
}

