import logger from '../utils/logger.js';
import { ethers } from 'ethers';
import api from '../utils/api.js';

class RiskAnalyzer {
  constructor(provider) {
    this.provider = provider;
  }

  async analyzeLiquidity(tokenAddress, routerAddress) {
    const pairAbi = ['function getReserves() external view returns (uint112, uint112, uint32)'];
    const router = new ethers.Contract(routerAddress, ['function factory() view returns (address)'], this.provider);
    const factoryAddress = await router.factory();
    const pairAddress = ethers.utils.getCreate2Address(factoryAddress, tokenAddress, ethers.constants.AddressZero);
    const pair = new ethers.Contract(pairAddress, pairAbi, this.provider);

    try {
      const [reserve0, reserve1] = await pair.getReserves();
      const locked = await pair.lockedLiquidity(); // Giả lập kiểm tra lock
      const liquidityEth = ethers.formatEther(reserve0.add(reserve1));
      const riskScore = liquidityEth < 10 || !locked ? 'Cao' : liquidityEth < 50 ? 'Trung bình' : 'Thấp';
      await logger(`Thanh khoản ${tokenAddress}: ${liquidityEth} ETH - Rủi ro: ${riskScore}`);
      return { liquidityEth, riskScore, locked };
    } catch (error) {
      return { liquidityEth: 0, riskScore: 'Rất cao', locked: false };
    }
  }

  async analyzeVolatility(tokenId) {
    const history = await api.getPriceHistory(tokenId);
    const prices = history.map(p => p.price);
    const avgPrice = prices.reduce((sum, p) => sum + p, 0) / prices.length;
    const variance = prices.reduce((sum, p) => sum + Math.pow(p - avgPrice, 2), 0) / prices.length;
    const volatility = Math.sqrt(variance);
    const riskScore = volatility > 0.5 ? 'Cao' : volatility > 0.2 ? 'Trung bình' : 'Thấp';
    await logger(`Biến động ${tokenId}: ${volatility} - Rủi ro: ${riskScore}`);
    return { volatility, riskScore };
  }

  async checkRugPull(tokenAddress) {
    const txs = await this.provider.getHistory(tokenAddress, null, null, 100); // Lấy 100 tx gần nhất
    const burnTxs = txs.filter(tx => tx.to === ethers.constants.AddressZero);
    const rugRisk = burnTxs.length > 5 ? 'Cao' : burnTxs.length > 1 ? 'Trung bình' : 'Thấp';
    await logger(`Kiểm tra rug-pull ${tokenAddress}: ${burnTxs.length} tx burn - Rủi ro: ${rugRisk}`);
    return { burnCount: burnTxs.length, rugRisk };
  }
}

export default RiskAnalyzer;

import logger from '../../utils/logger.js';
import { ethers } from 'ethers';
import { TonClient, JettonMaster, Address } from '@ton/ton';
import { Connection, PublicKey } from '@solana/web3.js';
import api from '../../utils/api.js';
import config from '../../config.js';

class TokenStatus {
  constructor(chain = 'evm', rpcUrl = config.rpcUrls.evm) {
    this.chain = chain;
    if (chain === 'evm') this.provider = new ethers.JsonRpcProvider(rpcUrl);
    else if (chain === 'ton') this.provider = new TonClient({ endpoint: rpcUrl });
    else if (chain === 'solana') this.provider = new Connection(rpcUrl);
  }

  // Lấy thông tin token
  async getTokenInfo(tokenAddress) {
    if (this.chain === 'evm') {
      const tokenAbi = [
        'function name() view returns (string)',
        'function symbol() view returns (string)',
        'function totalSupply() view returns (uint256)',
        'function decimals() view returns (uint8)'
      ];
      const token = new ethers.Contract(tokenAddress, tokenAbi, this.provider);
      try {
        const [name, symbol, totalSupply, decimals] = await Promise.all([
          token.name(),
          token.symbol(),
          token.totalSupply(),
          token.decimals()
        ]);
        const supplyFormatted = ethers.formatUnits(totalSupply, decimals);
        await logger(`Token ${tokenAddress}: ${name} (${symbol}), Total Supply: ${supplyFormatted}`);
        return { name, symbol, totalSupply: supplyFormatted, decimals };
      } catch (error) {
        await logger(`Lỗi kiểm tra token ${tokenAddress}: ${error.message}`, 'error');
        return null;
      }
    } else if (this.chain === 'ton') {
      const jetton = new JettonMaster(this.provider, Address.parse(tokenAddress));
      const data = await jetton.getJettonData();
      await logger(`Token TON ${tokenAddress}: ${data.name} (${data.symbol}), Total Supply: ${data.totalSupply}`);
      return { name: data.name, symbol: data.symbol, totalSupply: data.totalSupply.toString() };
    } else if (this.chain === 'solana') {
      const token = new PublicKey(tokenAddress);
      const info = await this.provider.getTokenSupply(token);
      await logger(`Token Solana ${tokenAddress}: Total Supply: ${info.value.uiAmountString}`);
      return { name: 'Unknown', symbol: 'Unknown', totalSupply: info.value.uiAmountString };
    }
  }

  // Kiểm tra honeypot và phân tích rủi ro
  async analyzeTokenRisk(tokenAddress) {
    const risks = { level: '🟢', details: [], score: 100 };

    // 1. Kiểm tra API bên ngoài (DexTools, RugCheck, Honeypot.is)
    await this.checkExternalAPIs(tokenAddress, risks);

    // 2. Kiểm tra hợp đồng (EVM-specific)
    if (this.chain === 'evm') {
      await this.checkEvmContract(tokenAddress, risks);
      await this.checkTransactionHistory(tokenAddress, risks);
    } else if (this.chain === 'ton') {
      await this.checkTonContract(tokenAddress, risks);
    } else if (this.chain === 'solana') {
      await this.checkSolanaContract(tokenAddress, risks);
    }

    // 3. Đánh giá mức độ rủi ro
    if (risks.score < 60 || risks.details.some(d => d.includes('🔴'))) {
      risks.level = '🔴';
    } else if (risks.score < 80) {
      risks.level = '🟡';
    }

    await logger(`Phân tích rủi ro ${tokenAddress}: ${risks.level} - Score: ${risks.score}`);
    return risks;
  }

  async checkExternalAPIs(tokenAddress, risks) {
    const apis = [
      { name: 'dextools', path: `/token/${this.chain}/${tokenAddress}/security` },
      { name: 'rugcheck', path: `/check/${tokenAddress}` },
      { name: 'honeypot', path: `/is-honeypot?address=${tokenAddress}&chain=${this.chain}` }
    ];

    for (const apiCheck of apis) {
      try {
        const data = await api.get(apiCheck.name, apiCheck.path);
        if (apiCheck.name === 'dextools') {
          if (data.isHoneypot || data.lockedLiquidity < 0.5) {
            risks.details.push('🔴 Honeypot hoặc thanh khoản khóa < 50% (DexTools)');
            risks.score -= 40;
          }
          risks.score = Math.max(0, Math.min(100, data.auditScore || risks.score));
        } else if (apiCheck.name === 'rugcheck' && data.riskLevel === 'high') {
          risks.details.push('🔴 Rủi ro cao (RugCheck)');
          risks.score -= 50;
        } else if (apiCheck.name === 'honeypot' && data.isHoneypot) {
          risks.details.push('🔴 Xác định honeypot (Honeypot.is)');
          risks.score -= 50;
        }
      } catch (error) {
        await logger(`Lỗi API ${apiCheck.name} cho ${tokenAddress}: ${error.message}`, 'warn');
      }
    }
  }

  async checkEvmContract(tokenAddress, risks) {
    const token = new ethers.Contract(tokenAddress, [
      'function balanceOf(address) view returns (uint256)',
      'function owner() view returns (address)',
      'function totalSupply() view returns (uint256)',
      'function decimals() view returns (uint8)',
      'function pause()',
      'function blacklistAddress(address)'
    ], this.provider);

    // Honeypot
    const deadBalance = await token.balanceOf('0x000000000000000000000000000000000000dEaD');
    if (deadBalance.gt(0)) {
      risks.details.push('🔴 Honeypot: Dead address có token');
      risks.score -= 50;
    }

    // Ownership
    const owner = await token.owner().catch(() => ethers.constants.AddressZero);
    if (owner === ethers.constants.AddressZero) {
      risks.details.push('🟡 Ownership từ bỏ hoặc ẩn');
      risks.score -= 20;
    } else {
      const ownerBalance = await token.balanceOf(owner);
      const totalSupply = await token.totalSupply();
      const ownershipPercent = ownerBalance.mul(100).div(totalSupply).toNumber();
      if (ownershipPercent > 50) {
        risks.details.push('🔴 Ownership > 50%: Tập trung cao');
        risks.score -= 30;
      }
    }

    // Pausable/Blacklist
    try {
      await token.pause();
      risks.details.push('🔴 Pausable: Có hàm pause()');
      risks.score -= 40;
    } catch {}
    try {
      await token.blacklistAddress(ethers.constants.AddressZero);
      risks.details.push('🔴 Blacklist: Có hàm chặn ví');
      risks.score -= 40;
    } catch {}

    // Liquidity
    const pairAddress = ethers.utils.getCreate2Address('0x5C69bEe701ef814a2B6a3EDD4B1652CB9cc5aA6f', tokenAddress, ethers.constants.AddressZero);
    const pair = new ethers.Contract(pairAddress, ['function getReserves() view returns (uint112, uint112, uint32)'], this.provider);
    const [reserve0, reserve1] = await pair.getReserves().catch(() => [0, 0]);
    const liquidityUsd = ethers.formatEther(reserve0.add(reserve1)) * 2000; // Giả lập giá ETH
    if (liquidityUsd < 1000) {
      risks.details.push('🔴 Thanh khoản < $1,000');
      risks.score -= 30;
    } else if (liquidityUsd > 10000) {
      risks.score += 20;
    }
  }

  async checkTransactionHistory(tokenAddress, risks) {
    const txs = await this.provider.getHistory(tokenAddress, null, null, 50); // 50 tx gần nhất
    const totalVolume = txs.reduce((sum, tx) => sum.add(tx.value || 0), ethers.BigNumber.from(0));
    const avgVolume = ethers.formatEther(totalVolume.div(txs.length));
    if (avgVolume > 100 && txs.length < 10) {
      risks.details.push('🔴 Volume giả: Giao dịch ít nhưng giá trị lớn');
      risks.score -= 30;
    }
  }

  async checkTonContract(tokenAddress, risks) {
    const jetton = new JettonMaster(this.provider, Address.parse(tokenAddress));
    const data = await jetton.getJettonData();
    const adminAddress = data.adminAddress?.toString() || '';
    const burnBalance = await jetton.getWalletData(Address.parse('EQAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAM9c')).then(wallet => wallet.balance);
    if (burnBalance.eq(0) && adminAddress === '') {
      risks.details.push('🔴 TON Honeypot: Không burn, không admin');
      risks.score -= 40;
    }
  }

  async checkSolanaContract(tokenAddress, risks) {
    const token = new PublicKey(tokenAddress);
    const mintInfo = await this.provider.getAccountInfo(token);
    const freezeAuthority = mintInfo.data.parsed.info.freezeAuthority;
    const mintAuthority = mintInfo.data.parsed.info.mintAuthority;
    if (!freezeAuthority || !mintAuthority) {
      risks.details.push('🔴 Solana Honeypot: Thiếu authority');
      risks.score -= 40;
    }
  }

  // Logic smart buy/sell
  async smartTrade(tokenAddress, amount, bot) {
    const risks = await this.analyzeTokenRisk(tokenAddress);
    switch (risks.level) {
      case '🔴':
        await logger(`Bỏ qua ${tokenAddress}: Rủi ro cao - ${risks.details.join(', ')}`);
        return { action: 'skip', reason: risks.details };
      case '🟡':
        await logger(`Mua thận trọng ${tokenAddress}: ${risks.score}`);
        const buyTx = await bot.buyToken(tokenAddress, amount);
        setTimeout(async () => {
          const priceHistory = await api.getPriceHistory(tokenAddress);
          const priceChange = (priceHistory[priceHistory.length - 1].price / priceHistory[0].price - 1) * 100;
          if (priceChange > 5) await bot.sellToken(tokenAddress, amount);
        }, 5 * 60 * 1000); // 5 phút
        return { action: 'buy', tx: buyTx };
      case '🟢':
        await logger(`Front-run ${tokenAddress}: ${risks.score}`);
        let trades = 0;
        bot.watchMempool(async (tx) => {
          if (trades < 3 && tx.value?.gt(ethers.parseEther('1'))) {
            const frontTx = await bot.buyToken(tokenAddress, amount);
            trades++;
            // Trailing Stop Loss (TSL)
            const tsl = setInterval(async () => {
              const price = await api.getTokenPrice(tokenAddress);
              if (price < price * 0.95) {
                await bot.sellToken(tokenAddress, amount);
                clearInterval(tsl);
              }
            }, 60000); // Kiểm tra mỗi phút
            return { action: 'front-run', tx: frontTx };
          }
        });
        return { action: 'front-run-started' };
    }
  }
}

export default TokenStatus;

import logger from '../../utils/logger.js';
import TokenStatus from './tokenStatus.js';
import RiskAnalyzer from './riskAnalyzer.js';
import optimizeGas from './gasOptimizer.js';
import NotificationService from '../../services/notificationService.js';
import { ethers } from 'ethers';

class TradeLogic {
  constructor({ chain, rpcUrl, tslConfig = { dropPercent: 5, checkInterval: 60000 }, role = 'free' }) {
    this.chain = chain;
    this.rpcUrl = rpcUrl;
    this.tslConfig = tslConfig;
    this.tokenStatus = new TokenStatus(chain, rpcUrl);
    this.riskAnalyzer = new RiskAnalyzer(this.createProvider(chain, rpcUrl));
    this.notificationService = new NotificationService({
      telegramToken: process.env.TELEGRAM_TOKEN,
      discordWebhook: process.env.DISCORD_WEBHOOK
    });
    this.role = role;
    this.tokenCache = new Map();
  }

  async initialize() {
    await this.notificationService.initialize();
  }

  createProvider(chain, rpcUrl) {
    if (chain === 'evm') return new ethers.JsonRpcProvider(rpcUrl);
    throw new Error(`Chain ${chain} chưa được hỗ trợ`);
  }

  // Manual Mode: Đánh giá token
  async evaluateToken(tokenInput) {
    const tokenAddress = await this.resolveTokenInput(tokenInput);
    const tokenInfo = await this.tokenStatus.getTokenInfo(tokenAddress);
    const risks = await this.riskAnalyzer.analyzeLiquidity(tokenAddress, this.getRouterAddress());
    this.tokenCache.set(`${this.chain}:${tokenAddress}`, risks);

    const log = {
      tokenInfo,
      risks,
      potential: risks.level === '🟢' ? 'Cao' : risks.level === '🟡' ? 'Trung bình' : 'Thấp'
    };
    await logger(`Đánh giá ${tokenAddress}: ${JSON.stringify(log)}`);
    return log;
  }

  async resolveTokenInput(input) {
    if (ethers.utils.isAddress(input)) return input;
    // TODO: Resolve qua API (CoinGecko) nếu là name/symbol
    throw new Error('Chưa hỗ trợ tìm token qua name/symbol');
  }

  // Manual Mode: Trade với gas tùy chỉnh
  async manualTrade(tokenAddress, amount, action, customGas, { buyToken, sellToken }) {
    const risks = this.tokenCache.get(`${this.chain}:${tokenAddress}`) || await this.riskAnalyzer.analyzeLiquidity(tokenAddress, this.getRouterAddress());
    const gasPrice = customGas || ((this.role === 'premium' || this.role === 'ultimate') ? await optimizeGas(this.createProvider(this.chain, this.rpcUrl)) : null);

    if (action === 'buy') {
      return this.executeSmartBuy(tokenAddress, amount, risks, { gasPrice }, { buyToken });
    } else if (action === 'sell') {
      return this.executeSmartSell(tokenAddress, amount, risks, { gasPrice }, { sellToken });
    }
  }

  // Auto Mode: Smart Buy
  async smartBuy(tokenAddress, amount, { buyToken, watchMempool }) {
    const risks = this.tokenCache.get(`${this.chain}:${tokenAddress}`) || await this.riskAnalyzer.analyzeLiquidity(tokenAddress, this.getRouterAddress());
    this.tokenCache.set(`${this.chain}:${tokenAddress}`, risks);
    const mempoolData = this.role === 'ultimate' ? await this.analyzeMempool(tokenAddress) : { potentialScore: 0 };
    return this.executeSmartBuy(tokenAddress, amount, risks, mempoolData, { buyToken, watchMempool });
  }

  async analyzeMempool(tokenAddress) {
    const provider = this.createProvider(this.chain, this.rpcUrl);
    const pendingTxs = [];
    await new Promise((resolve) => {
      provider.on('pending', async (txHash) => {
        const tx = await retry(() => provider.getTransaction(txHash));
        if (tx && tx.to === tokenAddress) pendingTxs.push(tx);
        if (pendingTxs.length >= 10) resolve();
      });
      setTimeout(resolve, 5000);
    });
    const volume = pendingTxs.reduce((sum, tx) => sum.add(tx.value || ethers.BigNumber.from(0)), ethers.BigNumber.from(0));
    const avgGas = pendingTxs.reduce((sum, tx) => sum.add(tx.gasPrice || ethers.BigNumber.from(0)), ethers.BigNumber.from(0)).div(pendingTxs.length || 1);
    const score = Math.min(100, pendingTxs.length * 10 + ethers.formatEther(volume) * 10 + ethers.formatUnits(avgGas, 'gwei') / 100);
    return { txCount: pendingTxs.length, volume: ethers.formatEther(volume), avgGas: ethers.formatUnits(avgGas, 'gwei'), potentialScore: score };
  }

  async executeSmartBuy(tokenAddress, amount, risks, mempoolData, { buyToken, watchMempool }) {
    const gasPrice = (this.role === 'premium' || this.role === 'ultimate') ? await optimizeGas(this.createProvider(this.chain, this.rpcUrl)) : null;

    switch (risks.level) {
      case '🔴':
        await logger(`Bỏ qua mua ${tokenAddress}: Rủi ro cao - ${risks.details.join(', ')}`);
        await this.notificationService.sendNotification(`🔴 Bỏ qua ${tokenAddress}: ${risks.details.join(', ')}`);
        return { action: 'skip', reason: risks.details };
      case '🟡':
        if (this.role === 'free') return { action: 'skip', reason: 'Free user không được phép mua token 🟡' };
        await logger(`Mua thận trọng ${tokenAddress}: Score ${risks.score}`);
        const buyTxYellow = await buyToken(this.chain, tokenAddress, amount, gasPrice);
        setTimeout(async () => {
          const priceHistory = await this.tokenStatus.api.getPriceHistory(tokenAddress);
          const priceChange = (priceHistory[priceHistory.length - 1].price / priceHistory[0].price - 1) * 100;
          if (priceChange > 5) {
            await this.sellToken(this.chain, tokenAddress, amount);
            await this.notificationService.sendNotification(`🟡 Bán ${tokenAddress}: Tăng ${priceChange}%`);
          }
        }, 5 * 60 * 1000);
        return { action: 'buy', tx: buyTxYellow };
      case '🟢':
        if (this.role === 'free' || this.role === 'premium') {
          await logger(`Mua cơ bản ${tokenAddress}: Score ${risks.score}`);
          const buyTxGreen = await buyToken(this.chain, tokenAddress, amount, gasPrice);
          return { action: 'buy', tx: buyTxGreen };
        }
        if (this.role === 'ultimate') {
          await logger(`Front-run mua ${tokenAddress}: Score ${risks.score}, Mempool Score ${mempoolData.potentialScore}`);
          await this.notificationService.sendNotification(`🟢 Bắt đầu front-run ${tokenAddress}`);
          watchMempool(async (tx) => {
            if (tx.value?.gt(ethers.parseEther('1'))) {
              const frontTx = await buyToken(this.chain, tokenAddress, amount, gasPrice);
              let lastPrice = await this.tokenStatus.api.getTokenPrice(tokenAddress);
              const tsl = setInterval(async () => {
                const currentPrice = await this.tokenStatus.api.getTokenPrice(tokenAddress);
                if (currentPrice < lastPrice * (1 - this.tslConfig.dropPercent / 100)) {
                  await this.sellToken(this.chain, tokenAddress, amount);
                  await this.notificationService.sendNotification(`🟢 TSL bán ${tokenAddress}: Giảm ${this.tslConfig.dropPercent}%`);
                  clearInterval(tsl);
                } else if (mempoolData.volume > 100 && currentPrice > lastPrice * 1.1) {
                  await buyToken(this.chain, tokenAddress, amount / 2, gasPrice);
                  await logger(`Mua thêm ${tokenAddress}: Pump mạnh`);
                }
                lastPrice = Math.max(lastPrice, currentPrice);
              }, this.tslConfig.checkInterval);
              return { action: 'front-run', tx: frontTx };
            }
          }, this.chain);
          return { action: 'front-run-started' };
        }
    }
  }

  // Auto Mode: Smart Sell
  async smartSell(tokenAddress, amount, { sellToken }) {
    const risks = this.tokenCache.get(`${this.chain}:${tokenAddress}`) || await this.riskAnalyzer.analyzeLiquidity(tokenAddress, this.getRouterAddress());
    this.tokenCache.set(`${this.chain}:${tokenAddress}`, risks);
    return this.executeSmartSell(tokenAddress, amount, risks, { sellToken });
  }

  async executeSmartSell(tokenAddress, amount, risks, { sellToken }) {
    const gasPrice = (this.role === 'premium' || this.role === 'ultimate') ? await optimizeGas(this.createProvider(this.chain, this.rpcUrl)) : null;
    switch (risks.level) {
      case '🔴':
        await logger(`Bỏ qua bán ${tokenAddress}: Rủi ro cao - ${risks.details.join(', ')}`);
        await this.notificationService.sendNotification(`🔴 Bỏ qua ${tokenAddress}: ${risks.details.join(', ')}`);
        return { action: 'skip', reason: risks.details };
      case '🟡':
      case '🟢':
        await logger(`Bán ${tokenAddress}: Score ${risks.score}`);
        const sellTx = await sellToken(this.chain, tokenAddress, amount, gasPrice);
        await this.notificationService.sendNotification(`✅ Bán ${tokenAddress} thành công`);
        return { action: 'sell', tx: sellTx };
    }
  }

  getRouterAddress() {
    return '0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D'; // Uniswap V2 Router
  }
}

