import { WebSocketServer } from 'ws';
import mqtt from 'mqtt';
import axios from 'axios';
import logger from '../utils/logger.js';
import retry from '../utils/retry.js';

class NotificationService {
  constructor({ wsPort = 8080, mqttUrl = 'mqtt://localhost:1883', telegramToken, discordWebhook }) {
    this.wss = new WebSocketServer({ port: wsPort });
    this.mqttClient = mqtt.connect(mqttUrl, { reconnectPeriod: 1000 });
    this.clients = new Map(); // Lưu client với token
    this.telegramToken = telegramToken;
    this.discordWebhook = discordWebhook;
  }

  async initialize() {
    this.wss.on('connection', (ws) => {
      ws.on('message', (msg) => {
        const { token } = JSON.parse(msg);
        if (token === 'VALID_TOKEN') this.clients.set(ws, token); // Xác thực đơn giản
      });
      ws.on('close', () => this.clients.delete(ws));
    });
    this.mqttClient.on('connect', () => logger('Kết nối MQTT thành công'));
    this.mqttClient.on('error', () => retry(() => this.mqttClient.reconnect()));
    await logger('NotificationService đã khởi tạo');
  }

  async sendNotification(message, channel = 'bot-updates') {
    const wsMessage = JSON.stringify({ channel, message });
    this.clients.forEach((token, client) => client.send(wsMessage));

    await retry(() => this.mqttClient.publish(channel, message));
    if (this.telegramToken) {
      await axios.post(`https://api.telegram.org/bot${this.telegramToken}/sendMessage`, {
        chat_id: 'YOUR_CHAT_ID',
        text: message
      });
    }
    if (this.discordWebhook) {
      await axios.post(this.discordWebhook, { content: message });
    }
    await logger(`Đã gửi thông báo: ${message}`);
  }

  async close() {
    this.wss.close();
    this.mqttClient.end();
  }
}

