import fs from 'fs/promises';

const logger = async (message, level = 'info') => {
  const timestamp = new Date().toISOString();
  const logMessage = `[${timestamp}] [${level.toUpperCase()}] ${message}`;

  // Ghi vào console
  console.log(logMessage);

  // Ghi vào file (tùy chọn)
  try {
    await fs.appendFile('server.log', `${logMessage}\n`);
  } catch (error) {
    console.error(`Lỗi ghi log vào file: ${error.message}`);
  }
};

export default logger;

async function retry(fn, retries = 3, delay = 1000) {
    for (let i = 0; i < retries; i++) {
      try {
        return await fn();
      } catch (error) {
        if (i === retries - 1) throw error;
        console.warn(`Thử lại lần ${i + 1} sau ${delay}ms: ${error.message}`);
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
  }
  
  export default retry;

