import express from 'express';
import https from 'https';
import fs from 'fs';
import jwt from 'jsonwebtoken';
import cors from 'cors';
import BotController from './backend/controllers/botController.js';
import UserController from './backend/controllers/userController.js';
import NotificationService from './backend/services/notificationService.js';
import logger from './backend/utils/logger.js';
import dotenv from 'dotenv';
import config from './backend/config.js';

dotenv.config();
const app = express();
app.use(express.json());
app.use(cors({ origin: 'https://your-frontend-url.com' })); // Cấu hình CORS cho Mini App

// Khởi tạo các service
const botController = new BotController({
  chain: 'evm',
  walletPrivateKey: process.env.WALLET_PRIVATE_KEY, // Bảo mật từ .env
  rpcUrl: process.env.RPC_EVM
});
const userController = new UserController();
const notificationService = new NotificationService({
  telegramToken: config.apiKeys.telegram, // Lấy từ config.js
  discordWebhook: config.apiKeys.discord   // Lấy từ config.js
});

// Middleware xác thực JWT
const authenticateJWT = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Token không được cung cấp' });
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    res.status(403).json({ error: 'Token không hợp lệ' });
  }
};

// API endpoints
app.get('/health', (req, res) => res.json({ status: 'OK', uptime: process.uptime() }));
app.get('/status', authenticateJWT, (req, res) => res.json({ state: botController.state }));
app.get('/balance', authenticateJWT, async (req, res) => {
  const balance = await botController.transactionService.bot.getBalance('evm');
  res.json({ balance });
});
app.post('/trade', authenticateJWT, async (req, res) => {
  const { action, tokenAddress, amount } = req.body;
  try {
    const tx = await botController.executeTrade({ action, tokenAddress, amount });
    await notificationService.sendNotification(`Trade ${action} ${tokenAddress}: ${tx.transactionHash || tx.txId}`);
    res.json(tx);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});
app.post('/login', async (req, res) => {
  const { walletAddress, signature } = req.body;
  try {
    const result = await userController.login(walletAddress, signature);
    res.json(result);
  } catch (error) {
    res.status(401).json({ error: error.message });
  }
});
app.post('/register', async (req, res) => {
  const { walletAddress, signature } = req.body;
  try {
    const result = await userController.registerUser(walletAddress, signature);
    res.json(result);
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

// Khởi động server với HTTPS
async function startServer() {
  try {
    await botController.start();
    await userController.initialize();
    await notificationService.initialize();
    await logger('Server đã khởi động');

    const httpsOptions = {
      key: fs.readFileSync(process.env.SSL_KEY_PATH || '/path/to/private.key'),
      cert: fs.readFileSync(process.env.SSL_CERT_PATH || '/path/to/certificate.crt')
    };
    https.createServer(httpsOptions, app).listen(3000, () => logger('Server HTTPS chạy trên port 3000'));
  } catch (error) {
    await logger(`Lỗi khởi động server: ${error.message}`, 'error');
    process.exit(1);
  }
}

startServer();
